@app.route("/econ/items", methods=["GET"])
def get_econ_items():
    """Fetch econ_gameplay_items.json from GitHub"""
    github_url = "https://raw.githubusercontent.com/FreakyUnity/moddedanimalcompany/refs/heads/main/game-data-prod/econ_gameplay_items.json"

    try:
        response = requests.get(github_url, timeout=5)
        response.raise_for_status()
        data = response.json()
        return jsonify(data)
    
    except requests.exceptions.RequestException as e:
        return jsonify({"error": f"Failed to fetch from GitHub: {str(e)}"}), 500


@app.route('/v2/rpc/mining.balance', methods=['GET'])
def mining_balance():
    response_body = {
        'payload': json.dumps({
            'hardCurrency': 20000000,
            'researchPoints': 999999
        })
    }
    return jsonify(response_body), 200

